window.Chart = window.Chart || function Chart(canvasId, config) {
  var canvas = typeof canvasId === 'string' ? document.getElementById(canvasId) : canvasId;
  if (!canvas || !canvas.getContext) return;
  var ctx = canvas.getContext('2d');
  var labels = (config && config.data && config.data.labels) || [];
  var datasets = (config && config.data && config.data.datasets) || [];
  var data = datasets[0] && datasets[0].data ? datasets[0].data : [];
  ctx.clearRect(0, 0, canvas.width, canvas.height);
  ctx.fillStyle = '#1f2937';
  ctx.font = '12px sans-serif';
  if (!data.length) { ctx.fillText('No chart data', 10, 20); return; }
  var max = Math.max.apply(null, data.concat([1]));
  var barWidth = Math.max(20, (canvas.width - 40) / data.length - 10);
  data.forEach(function (value, index) {
    var height = ((canvas.height - 60) * value) / max;
    var x = 30 + index * (barWidth + 10);
    var y = canvas.height - height - 30;
    ctx.fillStyle = (datasets[0].backgroundColor && datasets[0].backgroundColor[index]) || '#3b82f6';
    ctx.fillRect(x, y, barWidth, height);
    ctx.fillStyle = '#1f2937';
    ctx.fillText(labels[index] || '', x, canvas.height - 10);
  });
};
